 27→/// Default half-life for facts, in days.
 28→pub const FACT_HALF_LIFE_DAYS: f64 = 365.0;
 29→/// Default half-life for insights, in days.
 30→pub const INSIGHT_HALF_LIFE_DAYS: f64 = 30.0;
 31→/// Default half-life for heuristics, in days.
 32→pub const HEURISTIC_HALF_LIFE_DAYS: f64 = 90.0;
