 34→/// Semantic category for a knowledge item.
 35→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 36→#[serde(rename_all = "snake_case")]
 37→pub enum KnowledgeKind {
 38→    /// A declarative statement that is treated as true until contradicted.
 39→    Fact,
 40→    /// A compact causal observation distilled from multiple raw episodes.
 41→    Insight,
 42→    /// A step-by-step action pattern or recipe.
 43→    Procedure,
 44→    /// A lightweight rule of thumb or learned tendency.
 45→    Heuristic,
 46→    /// A compiled human-readable playbook of validated heuristics.
 47→    Playbook,
 48→    /// A hard restriction that should not be violated.
 49→    Constraint,
 50→    /// Negative knowledge describing what to avoid or what has failed.
 51→    AntiKnowledge,
 52→}
 53→
 54→impl Default for KnowledgeKind {
 55→    fn default() -> Self {
 56→        Self::Fact
 57→    }
 58→}
 59→
 60→impl KnowledgeKind {
 61→    /// Default temporal half-life for this kind of knowledge.
 62→    #[must_use]
 63→    pub const fn default_half_life_days(self) -> f64 {
 64→        match self {
 65→            Self::Fact => FACT_HALF_LIFE_DAYS,
 66→            Self::Insight => INSIGHT_HALF_LIFE_DAYS,
 67→            Self::Heuristic => HEURISTIC_HALF_LIFE_DAYS,
 68→            Self::Procedure | Self::Playbook | Self::Constraint | Self::AntiKnowledge => {
 69→                default_half_life_days()
 70→            }
 71→        }
 72→    }
 73→}
