 75→/// A durable unit of knowledge used for retrieval and memory.
 76→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 77→pub struct KnowledgeEntry {
 78→    /// Unique identifier for the knowledge item.
 79→    #[serde(default)]
 80→    pub id: String,
 81→    /// Knowledge category.
 82→    #[serde(default)]
 83→    pub kind: KnowledgeKind,
 84→    /// Provenance label for the entry, if it came from a dedicated source.
 85→    #[serde(default, skip_serializing_if = "Option::is_none")]
 86→    pub source: Option<String>,
 87→    /// The actual knowledge content.
 88→    #[serde(default)]
 89→    pub content: String,
 90→    /// Confidence score in the range `0.0..=1.0`.
 91→    #[serde(default = "default_confidence")]
 92→    pub confidence: f64,
 93→    /// Signed retrieval weight for the entry.
 94→    #[serde(default = "default_confidence_weight")]
 95→    pub confidence_weight: f64,
 96→    /// ID of the insight this entry refutes, if it is AntiKnowledge.
 97→    #[serde(default, skip_serializing_if = "Option::is_none")]
 98→    pub refuted_insight_id: Option<String>,
 99→    /// Evidence explaining why the refuted insight was wrong.
100→    #[serde(default, skip_serializing_if = "Option::is_none")]
101→    pub refutation_evidence: Option<String>,
102→    /// Episode IDs that contributed to this knowledge.
103→    #[serde(default)]
104→    pub source_episodes: Vec<String>,
105→    /// Topic tags used for retrieval and filtering.
106→    #[serde(default)]
107→    pub tags: Vec<String>,
108→    /// Which model originally produced the supporting episode(s), when
109→    /// this entry is model-specific.
110→    #[serde(default, skip_serializing_if = "Option::is_none")]
111→    pub source_model: Option<String>,
112→    /// How broadly this entry applies across models (`1.0` = fully
113→    /// general, `0.0` = only valid for one model family).
114→    #[serde(default = "default_model_generality")]
115→    pub model_generality: f64,
116→    /// Creation timestamp for the knowledge entry.
117→    #[serde(default = "Utc::now")]
118→    pub created_at: DateTime<Utc>,
119→    /// Exponential decay half-life in days.
120→    #[serde(default = "default_half_life_days")]
121→    pub half_life_days: f64,
122→    /// Optional HDC fingerprint for similarity search.
123→    #[serde(default)]
124→    pub hdc_vector: Option<Vec<u8>>,
125→}
126→
127→impl KnowledgeEntry {
128→    /// Return the warning text for an AntiKnowledge entry, if available.
129→    #[must_use]
130→    pub fn refutation_warning(&self) -> Option<String> {
131→        if self.kind != KnowledgeKind::AntiKnowledge {
132→            return None;
133→        }
134→
135→        let refuted_id = self.refuted_insight_id.as_deref()?.trim();
136→        if refuted_id.is_empty() {
137→            return None;
138→        }
139→
140→        let evidence = self
141→            .refutation_evidence
142→            .as_deref()
143→            .unwrap_or(self.content.as_str())
144→            .trim()
145→            .trim_end_matches(|ch| matches!(ch, '.' | '!' | '?'));
146→        if evidence.is_empty() {
147→            return None;
148→        }
149→
150→        Some(format!(
151→            "Previous insight {refuted_id} was wrong because {evidence}."
152→        ))
153→    }
154→
155→    /// Return whether the entry should be injected for `current_model`.
156→    #[must_use]
157→    pub fn applies_to_model(&self, current_model: &str) -> bool {
158→        self.model_generality > 0.7 || self.source_model.as_deref() == Some(current_model)
159→    }
160→}
