162→/// Single entry point for durable knowledge storage backends.
163→pub trait NeuroStore: Sized {
164→    /// Initialize a store at the given path.
165→    fn init(path: &Path) -> Result<Self>;
166→
167→    /// Query a topic for relevant knowledge entries.
168→    fn query(&self, topic: &str, limit: usize) -> Result<Vec<KnowledgeEntry>>;
169→
170→    /// Ingest a batch of knowledge entries.
171→    fn ingest(&mut self, entries: Vec<KnowledgeEntry>) -> Result<()>;
172→
173→    /// Apply decay and return the number of entries processed.
174→    fn decay(&mut self) -> Result<usize>;
175→
176→    /// Garbage-collect low-confidence entries and return the number removed.
177→    fn gc(&mut self, min_confidence: f64) -> Result<usize>;
178→}
