  1→//! `EpisodePolicy` — emits an Episode signal that ties a prompt, an agent
  2→//! output, and a set of gate verdicts together into one replayable record.
  3→
  4→use roko_core::{Body, Context, Decay, Kind, Policy, Provenance, Signal};
  5→
  6→/// A policy that wraps a full run (prompt → agent → gates) in one Episode signal.
  7→///
  8→/// Unlike the test-suite `EpisodePolicy` in `tests/`, this one emits a *single*
  9→/// Episode signal whose lineage points at the prompt, the agent output, and
 10→/// every gate verdict — i.e. the full run graph.
 11→pub struct EpisodePolicy {
 12→    name: String,
 13→}
 14→
 15→impl Default for EpisodePolicy {
 16→    fn default() -> Self {
 17→        Self {
 18→            name: "cli_episode".into(),
 19→        }
 20→    }
 21→}
 22→
 23→impl EpisodePolicy {
 24→    /// Construct a new episode policy.
 25→    #[must_use]
 26→    pub fn new() -> Self {
 27→        Self::default()
 28→    }
 29→
 30→    /// Build a single Episode signal for a completed run.
 31→    ///
 32→    /// The returned signal's lineage is `[prompt_id, agent_output_id, verdict_ids...]`.
 33→    /// Its body is a JSON summary of the run (pass/fail counts, agent success).
 34→    #[must_use]
 35→    pub fn record_run(
 36→        &self,
 37→        prompt: &Signal,
 38→        agent_output: &Signal,
 39→        agent_success: bool,
 40→        verdicts: &[Signal],
 41→        ctx: &Context,
 42→    ) -> Signal {
 43→        let passed = verdicts
 44→            .iter()
 45→            .filter(|v| v.tag("passed") == Some("true"))
 46→            .count();
 47→        let failed = verdicts
 48→            .iter()
 49→            .filter(|v| v.tag("passed") == Some("false"))
 50→            .count();
 51→
 52→        let summary = serde_json::json!({
 53→            "prompt_id": prompt.id.to_hex(),
 54→            "agent_output_id": agent_output.id.to_hex(),
 55→            "agent_success": agent_success,
 56→            "gates_passed": passed,
 57→            "gates_failed": failed,
 58→            "logged_at_ms": ctx.now_ms,
 59→        });
 60→
 61→        let mut lineage = vec![prompt.id, agent_output.id];
 62→        lineage.extend(verdicts.iter().map(|v| v.id));
 63→
 64→        let overall_pass = agent_success && failed == 0;
 65→
 66→        Signal::builder(Kind::Episode)
 67→            .body(Body::from_json(&summary).unwrap_or_else(|_| Body::empty()))
 68→            .provenance(Provenance::trusted(&self.name))
 69→            .lineage(lineage)
 70→            .decay(Decay::WISDOM)
 71→            .tag("passed", if overall_pass { "true" } else { "false" })
 72→            .tag("gates_passed", passed.to_string())
 73→            .tag("gates_failed", failed.to_string())
 74→            .build()
 75→    }
 76→}
 77→
 78→impl Policy for EpisodePolicy {
 79→    fn decide(&self, _stream: &[Signal], _ctx: &Context) -> Vec<Signal> {
 80→        // The CLI drives `record_run` directly; the streaming Policy API is
 81→        // unused here but implemented so `EpisodePolicy` still satisfies the
 82→        // trait contract for composition with future runtimes.
 83→        Vec::new()
 84→    }
 85→
 86→    fn name(&self) -> &str {
 87→        &self.name
 88→    }
 89→}
