 93→    use super::*;
 94→    use roko_core::{Body, Kind, Verdict};
 95→
 96→    fn verdict_sig(gate: &str, passed: bool) -> Signal {
 97→        Signal::builder(Kind::GateVerdict)
 98→            .body(Body::from_json(&Verdict::pass(gate)).unwrap_or(Body::empty()))
 99→            .tag("passed", if passed { "true" } else { "false" })
100→            .tag("gate", gate)
101→            .build()
102→    }
103→
104→    #[test]
105→    fn record_run_summarises_verdicts() {
106→        let policy = EpisodePolicy::new();
107→        let prompt = Signal::builder(Kind::Prompt).body(Body::text("p")).build();
108→        let out = Signal::builder(Kind::AgentOutput)
109→            .body(Body::text("o"))
110→            .build();
111→        let v1 = verdict_sig("g1", true);
112→        let v2 = verdict_sig("g2", false);
113→        let ep = policy.record_run(
114→            &prompt,
115→            &out,
116→            true,
117→            &[v1.clone(), v2.clone()],
118→            &Context::at(42),
119→        );
120→        assert_eq!(ep.kind, Kind::Episode);
121→        assert_eq!(ep.tag("gates_passed"), Some("1"));
122→        assert_eq!(ep.tag("gates_failed"), Some("1"));
123→        assert_eq!(ep.tag("passed"), Some("false"));
124→        assert!(ep.lineage.contains(&prompt.id));
125→        assert!(ep.lineage.contains(&out.id));
126→        assert!(ep.lineage.contains(&v1.id));
127→        assert!(ep.lineage.contains(&v2.id));
128→    }
