132→        let policy = EpisodePolicy::new();
133→        let prompt = Signal::builder(Kind::Prompt).body(Body::text("p")).build();
134→        let out = Signal::builder(Kind::AgentOutput)
135→            .body(Body::text("o"))
136→            .build();
137→        let ep = policy.record_run(
138→            &prompt,
139→            &out,
140→            true,
141→            &[verdict_sig("g", true)],
142→            &Context::at(0),
143→        );
144→        assert_eq!(ep.tag("passed"), Some("true"));
145→    }
