348→impl DreamCycle {
349→    /// Construct a dream cycle around the existing stores and dispatcher.
350→    #[must_use]
351→    pub fn new(
352→        episode_store: Arc<EpisodeLogger>,
353→        knowledge_store: Arc<KnowledgeStore>,
354→        playbook_store: Arc<PlaybookStore>,
355→        dispatcher: Arc<dyn AgentDispatcher>,
356→    ) -> Self {
357→        Self {
358→            episode_store,
359→            knowledge_store,
360→            playbook_store,
361→            dispatcher,
362→            last_dream_at: None,
363→        }
364→    }
365→
366→    /// Last completed cycle time, if any.
367→    #[must_use]
368→    pub const fn last_dream_at(&self) -> Option<DateTime<Utc>> {
369→        self.last_dream_at
370→    }
371→
372→    /// Override the last completed dream timestamp used to filter batches.
373→    pub fn set_last_dream_at(&mut self, last_dream_at: Option<DateTime<Utc>>) {
374→        self.last_dream_at = last_dream_at;
375→    }
376→
377→    /// Run a full offline learning pass.
378→    ///
379→    /// # Errors
380→    ///
381→    /// Returns an error if the episode log cannot be read, the stores cannot
382→    /// be updated, or the report cannot be written.
383→    pub async fn run(&mut self) -> Result<DreamCycleReport> {
384→        let started_at = Utc::now();
385→        let all_episodes = EpisodeLogger::read_all_lossy(self.episode_store.path())
386→            .await
387→            .with_context(|| {
388→                format!(
389→                    "read episode log from {}",
390→                    self.episode_store.path().display()
391→                )
392→            })?;
393→        let total_episodes = all_episodes.len();
394→        let cutoff = self.last_dream_at;
395→        let (historical, mut batch) = match cutoff {
396→            Some(cutoff) => all_episodes
397→                .into_iter()
398→                .partition(|episode| episode.timestamp <= cutoff),
399→            None => (Vec::new(), all_episodes),
400→        };
401→        batch.sort_by(|left, right| {
402→            left.timestamp
403→                .cmp(&right.timestamp)
404→                .then_with(|| left.id.cmp(&right.id))
405→        });
406→
407→        let processed_through = batch.iter().map(|episode| episode.timestamp).max();
408→        self.emit_success_rate_regression(&historical, &batch, started_at)?;
409→        let cfactor_regression = self.emit_cfactor_regression(started_at)?;
410→        let progression = TierProgression::default();
411→        let mut analysis = progression.analyze(&batch);
412→        progression.replay_heuristics(&mut analysis, &batch);
413→        let review_entries = review_insights_from_heuristics(&analysis, started_at);
414→        let performance_notes = performance_stall_notes(&batch);
415→        let mut clusters = cluster_episodes(batch);
416→        let mut written_knowledge_ids = BTreeSet::new();
417→
418→        let mut knowledge_entries_written = 0usize;
419→        let mut playbooks_created = 0usize;
420→        let mut regressions_detected = Vec::new();
421→
422→        for entry in review_entries {
423→            if written_knowledge_ids.insert(entry.id.clone()) {
424→                self.knowledge_store.add(entry.clone())?;
425→                knowledge_entries_written += 1;
426→            }
427→        }
428→
429→        for cluster in &mut clusters {
430→            let outcome = process_cluster(
431→                cluster,
432→                &self.dispatcher,
433→                &self.knowledge_store,
434→                &self.playbook_store,
435→                &mut written_knowledge_ids,
436→                started_at,
437→            )
438→            .await?;
439→            knowledge_entries_written += outcome.knowledge_entries_written;
440→            playbooks_created += usize::from(outcome.playbook_created);
441→            regressions_detected.extend(outcome.regression_entries.iter().cloned());
442→            cluster.knowledge_entries = outcome.knowledge_entries;
443→            cluster.playbook = outcome.playbook;
444→            cluster.regression_entries = outcome.regression_entries;
445→            cluster.agent_review = outcome.agent_review;
446→            cluster.warnings = outcome.warnings;
447→        }
448→
449→        let strategy_hypotheses = generate_cross_domain_strategy_hypotheses(&clusters, started_at);
450→        for hypothesis in &strategy_hypotheses {
451→            if written_knowledge_ids.insert(hypothesis.id.clone()) {
452→                self.knowledge_store.add(hypothesis.clone())?;
453→                knowledge_entries_written += 1;
454→            }
455→        }
456→
457→        let report = DreamCycleReport {
458→            started_at,
459→            completed_at: Utc::now(),
460→            total_episodes,
461→            processed_episodes: clusters.iter().map(|cluster| cluster.episode_count).sum(),
462→            processed_through,
463→            analysis,
464→            cfactor_regression,
465→            clusters: clusters.iter().map(DreamClusterReport::from).collect(),
466→            knowledge_entries_written,
467→            playbooks_created,
468→            regressions_detected,
469→            strategy_hypotheses,
470→            performance_notes,
471→        };
472→
473→        let counterfactuals = build_counterfactuals(&clusters, started_at);
474→        self.write_counterfactuals(&counterfactuals)?;
475→        self.write_report(&report).await?;
476→
477→        self.last_dream_at = Some(processed_through.unwrap_or(started_at));
478→
479→        Ok(report)
480→    }
481→
482→    fn emit_success_rate_regression(
483→        &self,
484→        historical: &[Episode],
485→        recent: &[Episode],
486→        started_at: DateTime<Utc>,
487→    ) -> Result<()> {
488→        let Some((historical_successes, historical_records, historical_rate)) =
489→            success_rate(historical)
490→        else {
491→            return Ok(());
492→        };
493→        let Some((recent_successes, recent_records, recent_rate)) = success_rate(recent) else {
494→            return Ok(());
495→        };
496→
497→        if historical_records < DREAMS_REGRESSION_MIN_RECORDS
498→            || recent_records < DREAMS_REGRESSION_MIN_RECORDS
499→            || historical_rate <= 0.0

