186→/// Trait for dream engines that can replay, consolidate, and schedule.
187→pub trait DreamEngine {
188→    /// Replay a batch of episodes into insights.
189→    fn replay(&mut self, episodes: &[Episode]) -> Result<Vec<Insight>>;
190→    /// Consolidate the workspace into a persisted dream report.
191→    fn consolidate(&mut self) -> Result<DreamReport>;
192→    /// Schedule the next dream fire time.
193→    fn schedule(&self) -> Option<Duration>;
194→}
195→
196→impl DreamEngine for DreamRunner {
197→    fn replay(&mut self, episodes: &[Episode]) -> Result<Vec<Insight>> {
198→        self.replay_insights(episodes)
199→    }
200→
201→    fn consolidate(&mut self) -> Result<DreamReport> {
202→        self.consolidate_now()
203→    }
204→
205→    fn schedule(&self) -> Option<Duration> {
206→        if !self.config.auto_dream {
207→            return None;
208→        }
209→
210→        let episodes_path = self.workdir.join(".roko").join("episodes.jsonl");
211→        let episodes = block_on(EpisodeLogger::read_all_lossy(&episodes_path)).ok()?;
212→        let last_report = load_latest_dream_report(&self.report_dir()).ok().flatten();
213→        let cutoff = last_report
214→            .as_ref()
215→            .and_then(|report| report.processed_through.or(Some(report.started_at)));
216→
217→        let recent: Vec<&Episode> = episodes
218→            .iter()
219→            .filter(|episode| cutoff.is_none_or(|ts| episode.timestamp > ts))
220→            .collect();
221→
222→        if recent.len() < self.config.min_episodes_for_dream {
223→            return None;
224→        }
225→
226→        let latest_episode = recent.iter().map(|episode| episode.timestamp).max()?;
227→        let idle_threshold =
228→            Duration::from_secs(self.config.idle_threshold_mins.saturating_mul(60));
229→        let target_fire_at = latest_episode + chrono::Duration::from_std(idle_threshold).ok()?;
230→        let now = Utc::now();
231→        if target_fire_at <= now {
232→            Some(Duration::ZERO)
233→        } else {
234→            (target_fire_at - now).to_std().ok()
235→        }
236→    }
237→}
