239→/// Load the latest persisted dream report from a report directory.
240→///
241→/// Returns `Ok(None)` when the directory has no report yet.
242→pub fn load_latest_dream_report(report_dir: &Path) -> Result<Option<DreamReport>> {
243→    let Some(path) = latest_dream_report_path(report_dir)? else {
244→        return Ok(None);
245→    };
246→    let text = std::fs::read_to_string(&path)
247→        .with_context(|| format!("read dream report {}", path.display()))?;
248→    let report: DreamReport = serde_json::from_str(&text)
249→        .with_context(|| format!("parse dream report {}", path.display()))?;
250→    Ok(Some(report))
251→}
252→
253→fn latest_dream_report_path(report_dir: &Path) -> Result<Option<PathBuf>> {
254→    let Ok(entries) = std::fs::read_dir(report_dir) else {
255→        return Ok(None);
256→    };
257→
258→    let mut latest: Option<(i64, PathBuf)> = None;
259→    for entry in entries {
260→        let entry = entry.with_context(|| format!("scan {}", report_dir.display()))?;
261→        let path = entry.path();
262→        if path.extension().and_then(|ext| ext.to_str()) != Some("json") {
263→            continue;
264→        }
265→        let Some(stem) = path.file_stem().and_then(|stem| stem.to_str()) else {
266→            continue;
267→        };
268→        let Some(ts) = stem.strip_prefix("dream-") else {
269→            continue;
270→        };
271→        let Ok(ts_ms) = ts.parse::<i64>() else {
272→            continue;
273→        };
274→        let should_replace = latest.as_ref().is_none_or(|(current, _)| ts_ms > *current);
275→        if should_replace {
276→            latest = Some((ts_ms, path));
277→        }
278→    }
279→
280→    Ok(latest.map(|(_, path)| path))
281→}
