283→fn block_on<F>(future: F) -> F::Output
284→where
285→    F: Future,
286→{
287→    if tokio::runtime::Handle::try_current().is_ok() {
288→        tokio::task::block_in_place(|| tokio::runtime::Handle::current().block_on(future))
289→    } else {
290→        let runtime = tokio::runtime::Builder::new_current_thread()
291→            .enable_all()
292→            .build()
293→            .expect("create dream runtime");
294→        runtime.block_on(future)
295→    }
296→}
