 28→/// Backend contract for episode distillation.
 29→#[async_trait]
 30→pub trait DistillationBackend: Send + Sync + std::fmt::Debug {
 31→    /// Run the backend on a fully rendered distillation prompt and
 32→    /// return the model's raw text response.
 33→    async fn complete(&self, prompt: &str) -> Result<String>;
