 42→    backend: Arc<dyn DistillationBackend>,
 43→}
 44→
 45→impl Distiller {
 46→    /// Construct a distiller backed by Anthropic Claude Haiku.
 47→    ///
 48→    /// The backend uses a small model by default so knowledge extraction
 49→    /// remains cheaper than a premium reasoning model.
 50→    #[must_use]
 51→    pub fn with_claude(api_key: impl Into<String>) -> Self {
 52→        Self::with_claude_model(api_key, DEFAULT_MODEL)
 53→    }
 54→
 55→    /// Construct a distiller backed by Anthropic Claude using an
 56→    /// explicit model slug.
 57→    #[must_use]
 58→    pub fn with_claude_model(api_key: impl Into<String>, model: impl Into<String>) -> Self {
 59→        Self::with_backend(Arc::new(ClaudeDistillationBackend::new(api_key, model)))
 60→    }
 61→
 62→    /// Construct a distiller from an arbitrary backend.
 63→    #[must_use]
 64→    pub fn with_backend(backend: Arc<dyn DistillationBackend>) -> Self {
 65→        Self { backend }
 66→    }
 67→
 68→    /// Return the configured model name.
 69→    #[must_use]
 70→    pub fn model(&self) -> &str {
 71→        self.backend.model()
 72→    }
 73→
 74→    /// Distill a batch of episodes into knowledge candidates.
 75→    ///
 76→    /// # Errors
 77→    ///
 78→    /// Returns an error if prompt construction fails, the backend fails,
 79→    /// or the model response cannot be parsed as structured output.
 80→    pub async fn distill(&self, episodes: &[Episode]) -> Result<Vec<KnowledgeEntry>> {
 81→        if episodes.is_empty() {
 82→            return Ok(Vec::new());
 83→        }
 84→
 85→        let prompt = build_prompt(episodes)?;
 86→        let response = self
 87→            .backend
 88→            .complete(&prompt)
 89→            .await
 90→            .with_context(|| format!("distillation backend {} failed", self.model()))?;
 91→        let envelope = parse_distillation_response(&response)?;
 92→        Ok(envelope.into_entries(episodes))
 93→    }
 94→}
