113→#[async_trait]
114→impl DistillationBackend for ClaudeDistillationBackend {
115→    async fn complete(&self, prompt: &str) -> Result<String> {
116→        let signal = Signal::builder(Kind::Prompt)
117→            .body(Body::text(prompt))
118→            .provenance(Provenance::agent("roko-neuro:distiller"))
119→            .build();
120→        let result = self.agent.run(&signal, &RokoContext::now()).await;
121→        if !result.success {
122→            let reason = result
123→                .output
124→                .body
125→                .as_text()
126→                .map(str::to_owned)
127→                .unwrap_or_else(|_| "distillation model returned a non-text failure".to_string());
128→            return Err(anyhow!(reason));
129→        }
130→
131→        result
132→            .output
133→            .body
134→            .as_text()
135→            .map(str::to_owned)
136→            .map_err(|err| anyhow!("distillation response was not text: {err}"))
137→    }
138→
139→    fn model(&self) -> &str {
140→        &self.model
141→    }
142→}
