681→fn read_cfactor_history(path: &Path) -> Result<Vec<CFactor>> {
682→    let text = match std::fs::read_to_string(path) {
683→        Ok(text) => text,
684→        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
685→        Err(error) => {
686→            return Err(error).with_context(|| format!("read C-Factor history {}", path.display()));
687→        }
688→    };
689→
690→    let mut history = Vec::new();
691→    for line in text.lines() {
692→        let trimmed = line.trim();
693→        if trimmed.is_empty() {
694→            continue;
695→        }
696→        if let Ok(snapshot) = serde_json::from_str::<CFactor>(trimmed) {
697→            history.push(snapshot);
698→        }
699→    }
700→    Ok(history)
701→}
