        match self {
            Self::Fact => 365.0,           // FACT_HALF_LIFE_DAYS
            Self::Insight => 30.0,         // INSIGHT_HALF_LIFE_DAYS
            Self::Heuristic => 90.0,       // HEURISTIC_HALF_LIFE_DAYS
            Self::Procedure | Self::Playbook | Self::Constraint | Self::AntiKnowledge => 30.0,
        }
    }
}
