    pub label: String,
    /// Node indices in this cluster
    pub members: Vec<usize>,
    /// Tier distribution within the cluster
    pub tier_distribution: TierDistribution,
    /// Kind distribution
    pub kind_distribution: HashMap<String, usize>,
}

